var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"숲……?","JPN":"森……？","ENG":"A forest...?","TWN":"森林……？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"진짜 부자는 저택 내부에도 숲을 둘 수 있나?","JPN":"本物のお金持ちって、邸宅の内部にも森を持てるものなのか？","ENG":"Can rich people really afford to have forests inside their mansions?","TWN":"真正的有錢人連在屋裡造森林也沒問題嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 아니야…… 루시아 생각해 봐…….","JPN":"いや、違う……ルシア、考えるんだ……","ENG":"No, no... Lucia, think...","TWN":"啊，不是的……露西卡，想一想……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이건 침식파의 냄새잖아.","JPN":"これは侵食波の匂いだろ。","ENG":"This is the stench of Corruption.","TWN":"這是侵蝕波的氣味啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"영지에 무단으로 침입하는 사람들을 어떻게 될까?","JPN":"領地に無断侵入した人たちはどうなるでしょう？","ENG":"What happens to intruders who sneak into an estate?","TWN":"擅自闖入領地的人會怎麼樣？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"평생을 숲속에서 헤매다가 죽게 됩니다!","JPN":"一生森の中で彷徨って死にます！","ENG":"They wander the forest for the rest of their lives... until they die!","TWN":"你會一輩子在森林裡徘徊，直到死去！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L14_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"그럼 어떤 원리로 숲속을 헤매게 만들지?","JPN":"じゃあ、侵入者はどうしたら森の中を彷徨うことになるのかしら、ワンちゃん？","ENG":"Then, how can we make them wander the forest?","TWN":"那麼，究竟是用什麼原理讓人在森林中迷路的呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"우선, 침식파가 유입되는 환경을 만듭니다!","JPN":"まずは、侵食波が流れ込む環境を作ります！","ENG":"First, you create an environment that lets the Corruption seep in!","TWN":"首先，製造出有侵蝕波湧入的環境！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"그런 뒤 기괴한 소문이나 불길한 징조를 유포하면 완성입니다!","JPN":"その後、奇怪な噂や不吉な兆候を流せば完成です！","ENG":"Then, you spread eerie rumors and ominous signs... and it's complete!","TWN":"然後散佈一些奇怪的傳聞或不祥的預兆就完成了！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"잘했어. 상으로 에그타르트 한 개~","JPN":"よくできました。ご褒美にエッグタルト1個～","ENG":"Good job. Here, have an egg tart!","TWN":"很好，獎勵你一個蛋撻～"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저택에 침식파가 유입된 거야.","JPN":"邸宅に侵食波が流れ込んだんだ。","ENG":"So the Corruption seeped into the estate...","TWN":"侵蝕波流入了屋子。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 어떻게……?","JPN":"でも、どうやって……？","ENG":"But how...?","TWN":"但是怎麼會……？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"중심부로 들어온 것 같군.","JPN":"中心部に入ったようだな。","ENG":"Looks like you've reached the core of the mansion.","TWN":"好像進入到了中心。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"형제님……? 어떻게 연락을……?","JPN":"ブラザー……？　どうやって連絡を……？","ENG":"Brother Ludwig? How did you manage to contact me?","TWN":"弟兄……？怎麼聯絡……？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"안쪽은 본래 내가 연구실로 쓰던 곳이네.","JPN":"奥は本来私が研究室として使っていたところだ。","ENG":"That area used to be my personal research lab.","TWN":"裡面原本是我用作研究室的地方。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"침식파를 연구하니, 환경에 맞는 통신 수단을 갖출 수밖에.","JPN":"侵食波を研究していたから、環境に合う通信方法を備えている。","ENG":"Since I studied Corruption rays, I had no choice but to set up a communication system suited for that environment.","TWN":"既然研究侵蝕波，就不得不配備適應環境的通訊方法。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"덤으로…… 내가 침식 증후군에 시달린 이유이기도 하네.","JPN":"ちなみに……私が侵食症候群で苦しんでいた理由でもある。","ENG":"And... well, it's also the reason I developed Corruption Syndrome.","TWN":"順便說一下……這也是我飽受侵蝕症候群折磨的原因。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하긴, 이런 환경에서 멀쩡한 게 오히려 이상하죠.","JPN":"まあ、こんな環境で何ともない方がおかしいでしょうね。","ENG":"Yeah, figures. Staying okay in this mess would be weirder.","TWN":"也是，在這種環境下還能正常才奇怪呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"우리 수도원은 호스피스 병동도 운영하고 있습니다.","JPN":"私共の修道院はホスピス病棟も運営しています。","ENG":"Our monastery also runs a hospice ward, by the way.","TWN":"我們修道院還有經營安寧病房。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"혹시 관심이 있으신가요?","JPN":"ご興味がおありでしょうか？","ENG":"Are you interested?","TWN":"你感興趣嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"기회가 되면 알아보도록 하겠네. 하지만 지금은 아니야.","JPN":"機会があれば調べてみるとしよう。だが、今ではない。","ENG":"Maybe someday. But not now.","TWN":"有機會的話我會去了解的，但現在還不行。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"혹시 관리인들도 침식 증후군으로 헛것을 본 건 아닐까요?","JPN":"もしかして管理人の方々も侵食症候群で幻覚を経験したのでは？","ENG":"Could it be that the caretakers were just hallucinating from the Corruption Syndrome?","TWN":"難道管理員們也是因為侵蝕症候群而產生了幻覺嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그럴지도 모르지.","JPN":"そうかもしれない。","ENG":"Possibly.","TWN":"也許吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"하지만 난 저택의 잠재적 위협을 확인할 의무가 있네.","JPN":"だが、私には邸宅の潜在的な脅威を確認する義務がある。","ENG":"But I have an obligation to assess all potential threats to my estate.","TWN":"但是我有義務確認屋子的潛在威脅。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그래서 전문가인 자네를 고용한 거고.","JPN":"だから専門家である君を雇用した。","ENG":"That's why I hired you, a professional.","TWN":"所以才會請你這個專家來。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"자네도 침식파의 영향을 받았을 수도 있으니 묻겠네.","JPN":"君も侵食波に影響されているかもしれないから、聞くとしよう。","ENG":"And since you're also exposed to Corruption rays, let me ask.","TWN":"你可能也受到了侵蝕波的影響，所以我問一下。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"이곳에 들어오고 나서 어지럽다거나, 몸이 뜨거운 증상은 없었나?","JPN":"そこに入ってから目眩がしたり、体が熱くなる症状はなかったかね？","ENG":"Since entering that space, have you felt dizzy? Feverish?","TWN":"進入這裡之後有沒有感到頭暈，或者身體發熱？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L49_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그곳에서 발생하는 침식파는 사람의 몸을 변질시키거든.","JPN":"そこで発生する侵食波は人の体を変質させる。","ENG":"The Corruption rays in that area... they alter the human body.","TWN":"那裡產生的侵蝕波會使人的身體變質。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"동공이 수축하고, 털과 손톱이 자라나지.","JPN":"瞳孔が収縮し、毛と爪が長くなる。","ENG":"The pupils constrict, fur and nails grow unnaturally long.","TWN":"瞳孔收縮，毛髮和指甲生長。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"이성을 잃은 개체는 물을 무서워하게 되고, 빛에 한없이 약해져.","JPN":"理性を失った個体は水を怖がり、限りなく光に弱くなる。","ENG":"Those who lose their minds fear water and become weak to light.","TWN":"失去理智的個體會害怕水，對光極其敏感。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그리고 결정적으로 피가 끓는 듯한 고통을 느끼며 미쳐버린다네.","JPN":"そして決定的に血が沸くような苦痛を感じながら狂ってしまうのだ。","ENG":"And the worst part. They suffer unbearable pain, as if their blood is boiling, until they go completely insane.","TWN":"最終會感受到血液沸騰般的痛苦，徹底瘋狂。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이럴 시간 없어요.","JPN":"こうしている時間はありません。","ENG":"I don't have time for this.","TWN":"我沒時間跟你閒聊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"지금도 어딘가엔 악령이 빙의된 수녀가 돌아다니는…….","JPN":"今もどこかで悪霊に憑りつかれたシスターが歩き回って……","ENG":"There's still a possessed nun wandering around somewhere–","TWN":"現在某個地方還有被惡靈附身的修女在遊蕩……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"여기서 연구한 건 조금 색다른 침식파거든.","JPN":"私が研究したのはちょっと変わった侵食波でね。","ENG":"The Corruption rays I studied here are a bit different.","TWN":"這裡研究的是有點特別的侵蝕波。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그래서 반드시 자네의 상태를 확인해야만 하네.","JPN":"だから必ず君の状態を確認する必要があるのだ。","ENG":"That's why I need to check your sickness.","TWN":"所以必須確認你的狀態。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"<color=#ffd34c>10년 전</color>에 처음 관측되었다는 <color=#ffd34c>이상 침식 현상</color>에 대해 알고 있나?","JPN":"<color=#ffd34c>10年前</color>に初めて観測されたという<color=#ffd34c>異常侵食現象</color>について知っているかね？","ENG":"Have you heard of the <color=#ffd34c>Aberrant Counterside Effect</color> that was first observed <color=#ffd34c>ten years ago</color>?","TWN":"<color=#ffd34c>10年前</color>首次觀測到的<color=#ffd34c>異常侵蝕現象</color>，你知道嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"형제님! 전 퇴마사지, 침식학 박사 과정이 아니라고요!","JPN":"ブラザー！　私はエクソシストであって、侵食学の院生ではありません！","ENG":"I'm an exorcist! I don't have a PhD in Corruption!","TWN":"弟兄！我是驅魔師，不是侵蝕學博士生啊！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"연구 성과를 자랑할 사람이 없어서 그래요?","JPN":"研究成果を自慢する相手がいないからなのですか？","ENG":"Are you just frustrated that you have no one to nerd out with?","TWN":"是因為沒人聽你炫耀你的研究成果嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"제가 나중에 다~ 들어드릴게요.","JPN":"そういうことでしたら、私が後ほど全部聞いてさしあげますから。","ENG":"I'll gladly listen to all your findings later.","TWN":"等事成之後，你再慢慢說給我聽～"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"물론 유료지만.","JPN":"もちろんお金はいただきますが。","ENG":"Of course, it's not free.","TWN":"當然是要收錢的囉。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"……그런가.","JPN":"……そうか。","ENG":"...I see.","TWN":"……是嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"집에만 박혀 있었더니 나쁜 버릇이 박힌 모양이야.","JPN":"家に閉じこもってばかりいたからか悪い癖がついてしまったようだ。","ENG":"I suppose being cooped up has given me some bad habits.","TWN":"一直待在家裡，好像養成了壞習慣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"방구석에만 박혀 있으면 사람의 정신에 좋지 않습니다.","JPN":"部屋に閉じこもってばかりいると、人間の精神に良くありませんよ。","ENG":"Staying locked inside all the time does mess with your head.","TWN":"一直窩在房間裡對人的精神不好。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"악령은 그럼 사람들을 노리는 경우가 다반사거든요.","JPN":"悪霊はそんな人たちを狙う場合が多いですから。","ENG":"That's exactly the kind of person evil spirits love to target.","TWN":"惡靈經常盯上人類。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"결국 이 저택에 악령이 깃든 것도 내가 다 자초한 일이라는 거군.","JPN":"結局この邸宅に悪霊が巣食ってしまったのも、私のせいということか。","ENG":"So in the end, my mansion being haunted is just a result of my own choices.","TWN":"這座屋子最終被惡靈依附是我一手造成的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네. 하지만 너무 자책하지 마세요.","JPN":"はい。ですが、あまりご自分をお責めにならないでください。","ENG":"Pretty much. But hey, don't beat yourself up over it.","TWN":"對，但是不要太自責了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"우리 수도원은 형제님 같은 사람을 위한 재활 코스도 준비되어 있거든요.","JPN":"私共の修道院はブラザーのような方のためにリハビリコースもご用意しております。","ENG":"Our monastery offers rehabilitation courses for people just like you.","TWN":"我們修道院還為像弟兄你這樣的人準備了康復課程。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"형제님은 제 호구……가 아니라 VIP 고객이 되었으니 할인가가 적용됩니다.","JPN":"ブラザーは私のカモ……ではなくVIPになられましたので割引価格が適用されます。","ENG":"Since you're my, uh, VIP client, I'll even give you a discount.","TWN":"弟兄你已經成為了我的盤子……不是，是VIP客戶，所以可以享受折扣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"할인가……?","JPN":"割引価格……？","ENG":"...A discount?","TWN":"折扣價……？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무려 원가 10% 할인!","JPN":"なんと10％割引！","ENG":"A whole 10% off!","TWN":"打九折喔！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하~ 이러면 손해만 보는데, 형제님이니까 특별히 해드리는 거예요.","JPN":"は～これでは赤字になってしまいますが、ブラザーですから特別です。","ENG":"*Sigh* I'm practically taking a loss here, but for you, I'll make an exception.","TWN":"哈～這樣的話我就虧了，不過因為是弟兄才給優惠喔。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"대단하군. 10% 할인이라…….","JPN":"すごいな。10％割引か……","ENG":"10%, you say...","TWN":"好棒，還打九折……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"하지만 자네가 무사히 일을 마쳐야 할 수 있는 얘기겠지.","JPN":"だが、君が無事仕事を終えられたらの話だな。","ENG":"But first, you'll have to survive and finish the job.","TWN":"但這得等你平安完成任務後才有。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"서둘러 주게. 더 이상의 사상자는 원하지 않으니.","JPN":"急いでくれたまえ。これ以上の死傷者は御免だ。","ENG":"Hurry. I won't accept any more casualties.","TWN":"快點吧，我不希望再有更多的傷亡了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};